diff --git a/src/search/engine.js b/src/search/engine.js
index 463f139..07c8637 100644
--- a/src/search/engine.js
+++ b/src/search/engine.js
@@ -15,12 +15,17 @@ function search(query, documents) {
     let score = 0;
     const content = doc.content || '';

+    // Optimization: Process document content once to count word frequencies
+    const words = content.toLowerCase().split(/\s+/).filter(Boolean);
+    const wordCounts = {};
+    for (const word of words) {
+        wordCounts[word] = (wordCounts[word] || 0) + 1;
+    }
+
+    // Calculate score by summing the frequency of each search term
     for (const term of terms) {
-      // BUG: re-splitting the document content for EVERY term creates O(terms * words) work
-      // per document, making the total complexity O(docs * terms * words)
-      const words = content.toLowerCase().split(/\s+/);
-      for (const word of words) {
-        if (word === term) score++;
+      if (wordCounts[term]) {
+        score += wordCounts[term];
       }
     }
